#nullable enable
using Microsoft.AspNetCore.Mvc; using PluginEngine.Services.Abstractions; namespace PluginEngine.Controllers { [ApiController] [Route("[controller]")] public sealed class HealthController : ControllerBase { private readonly IPluginManagerService _pluginManagerService; public HealthController(IPluginManagerService pluginManagerService) { _pluginManagerService = pluginManagerService; } [HttpGet] public async Task<IActionResult> GetHealthAsync() { var status = await _pluginManagerService.GetStatusAsync(); return Ok(status); } [HttpGet("ready")] public async Task<IActionResult> GetReadyAsync() { var status = await _pluginManagerService.GetStatusAsync(); if (status.IsInitialized && status.LoadedPlugins > 0) { return Ok(status); } return StatusCode(503); } } }